CREATE OR REPLACE EDITIONABLE FUNCTION "TOPSPORTS"."F_GET_PYJM" (P_NAME IN VARCHAR2) RETURN VARCHAR2 AS
  V_COMPARE VARCHAR2(100);
  V_RETURN  VARCHAR2(4000);
BEGIN
  DECLARE
    FUNCTION F_NLSSORT(P_WORD IN VARCHAR2) RETURN VARCHAR2 AS
    BEGIN
      RETURN NLSSORT(P_WORD, 'NLS_SORT=SCHINESE_PINYIN_M');
    END;
  BEGIN
    FOR I IN 1 .. LENGTH(P_NAME) LOOP
      V_COMPARE := F_NLSSORT(SUBSTR(P_NAME, I, 1));

      IF V_COMPARE >= F_NLSSORT('吖') AND V_COMPARE <= F_NLSSORT('驁') THEN
        V_RETURN := V_RETURN || 'A';
      ELSIF V_COMPARE >= F_NLSSORT('八') AND V_COMPARE <= F_NLSSORT('簿') THEN
        V_RETURN := V_RETURN || 'B';
      ELSIF V_COMPARE >= F_NLSSORT('嚓') AND V_COMPARE <= F_NLSSORT('錯') THEN
        V_RETURN := V_RETURN || 'C';
      ELSIF V_COMPARE >= F_NLSSORT('咑') AND V_COMPARE <= F_NLSSORT('鵽') THEN
        V_RETURN := V_RETURN || 'D';
      ELSIF V_COMPARE >= F_NLSSORT('妸') AND V_COMPARE <= F_NLSSORT('樲') THEN
        V_RETURN := V_RETURN || 'E';
      ELSIF V_COMPARE >= F_NLSSORT('发') AND V_COMPARE <= F_NLSSORT('猤') THEN
        V_RETURN := V_RETURN || 'F';
      ELSIF V_COMPARE >= F_NLSSORT('旮') AND V_COMPARE <= F_NLSSORT('腂') THEN
        V_RETURN := V_RETURN || 'G';
      ELSIF V_COMPARE >= F_NLSSORT('妎') AND V_COMPARE <= F_NLSSORT('夻') THEN
        V_RETURN := V_RETURN || 'H';
      ELSIF V_COMPARE >= F_NLSSORT('丌') AND V_COMPARE <= F_NLSSORT('攈') THEN
        V_RETURN := V_RETURN || 'J';
      ELSIF V_COMPARE >= F_NLSSORT('咔') AND V_COMPARE <= F_NLSSORT('穒') THEN
        V_RETURN := V_RETURN || 'K';
      ELSIF V_COMPARE >= F_NLSSORT('垃') AND V_COMPARE <= F_NLSSORT('擽') THEN
        V_RETURN := V_RETURN || 'L';
      ELSIF V_COMPARE >= F_NLSSORT('嘸') AND V_COMPARE <= F_NLSSORT('椧') THEN
        V_RETURN := V_RETURN || 'M';
      ELSIF V_COMPARE >= F_NLSSORT('拏') AND V_COMPARE <= F_NLSSORT('瘧') THEN
        V_RETURN := V_RETURN || 'N';
      ELSIF V_COMPARE >= F_NLSSORT('筽') AND V_COMPARE <= F_NLSSORT('漚') THEN
        V_RETURN := V_RETURN || 'O';
      ELSIF V_COMPARE >= F_NLSSORT('妑') AND V_COMPARE <= F_NLSSORT('曝') THEN
        V_RETURN := V_RETURN || 'P';
      ELSIF V_COMPARE >= F_NLSSORT('七') AND V_COMPARE <= F_NLSSORT('裠') THEN
        V_RETURN := V_RETURN || 'Q';
      ELSIF V_COMPARE >= F_NLSSORT('亽') AND V_COMPARE <= F_NLSSORT('鶸') THEN
        V_RETURN := V_RETURN || 'R';
      ELSIF V_COMPARE >= F_NLSSORT('仨') AND V_COMPARE <= F_NLSSORT('蜶') THEN
        V_RETURN := V_RETURN || 'S';
      ELSIF V_COMPARE >= F_NLSSORT('侤') AND V_COMPARE <= F_NLSSORT('籜') THEN
        V_RETURN := V_RETURN || 'T';
      ELSIF V_COMPARE >= F_NLSSORT('屲') AND V_COMPARE <= F_NLSSORT('鶩') THEN
        V_RETURN := V_RETURN || 'W';
      ELSIF V_COMPARE >= F_NLSSORT('夕') AND V_COMPARE <= F_NLSSORT('鑂') THEN
        V_RETURN := V_RETURN || 'X';
      ELSIF V_COMPARE >= F_NLSSORT('丫') AND V_COMPARE <= F_NLSSORT('韻') THEN
        V_RETURN := V_RETURN || 'Y';
      ELSIF V_COMPARE >= F_NLSSORT('帀') AND V_COMPARE <= F_NLSSORT('咗') THEN
        V_RETURN := V_RETURN || 'Z';
      ELSE
        V_RETURN := V_RETURN || UPPER(SUBSTR(P_NAME, I, 1));
      END IF;
    END LOOP;
    RETURN UPPER(V_RETURN);
  END;
END;

CREATE OR REPLACE EDITIONABLE FUNCTION "TOPSPORTS"."FN_R_REFCUR" (P_VALUE IN VARCHAR2)
  RETURN TYPE_TEMP_TABLE IS
  type my_cursor is ref cursor;
  C_CUR my_cursor;
  ID number;
  TITLE varchar2(100);
  TEMP_TABLE TYPE_TEMP_TABLE := TYPE_TEMP_TABLE();
  TEMP_ROW TYPE_TTEMP_ROW;
BEGIN
  OPEN C_CUR for P_VALUE;

  LOOP
    fetch C_CUR into ID,TITLE;
    Exit when C_CUR%notfound;
    TEMP_ROW := TYPE_TTEMP_ROW(ID,TITLE);
    TEMP_TABLE.EXTEND;
    TEMP_TABLE(TEMP_TABLE.COUNT) := TEMP_ROW;
  END LOOP;
  close C_CUR;
  RETURN(TEMP_TABLE);
END;

CREATE OR REPLACE EDITIONABLE FUNCTION "TOPSPORTS"."MCFN_DATECALCYEAR" ( v_begindate IN DATE, v_enddate IN DATE, v_xtype IN NUMBER ) RETURN NUMBER AS ---@xtype = 1-? 2-? 3-? v_ret NUMBER(18,0);
BEGIN IF v_xtype = 1 THEN
BEGIN v_ret := case when add_months(v_begindate,12*datediff('YYYY',to_char(v_begindate,'YYYY-MM-DD'),to_char(v_enddate,'YYYY-MM-DD'))) > v_enddate then datediff('YYYY',to_char(v_begindate,'YYYY-MM-DD'),to_char(v_enddate,'YYYY-MM-DD')) - (datediff('D',to_char(v_enddate,'YYYY-MM-DD'),to_char(add_months(v_begindate,12*datediff('YYYY',to_char(v_begindate,'YYYY-MM-DD'),to_char(v_enddate,'YYYY-MM-DD'))),'YYYY-MM-DD'))+1) * 1.0000 / (datediff('D',to_char(mcfn_date(v_enddate,1),'YYYY-MM-DD'),to_char(mcfn_date(v_enddate,2),'YYYY-MM-DD'))+1) when add_months(v_begindate,12*datediff('YYYY',to_char(v_begindate,'YYYY-MM-DD'),to_char(v_enddate,'YYYY-MM-DD'))) <= v_enddate then datediff('YYYY',to_char(v_begindate,'YYYY-MM-DD'),to_char(v_enddate,'YYYY-MM-DD')) + (datediff('D',to_char(add_months(v_begindate,12*datediff('YYYY',to_char(v_begindate,'YYYY-MM-DD'),to_char(v_enddate,'YYYY-MM-DD'))),'YYYY-MM-DD'),to_char(v_enddate,'YYYY-MM-DD'))+1) * 1.0000 / (datediff('D',to_char(mcfn_date(v_enddate,1),'YYYY-MM-DD'),to_char(mcfn_date(v_enddate,2),'YYYY-MM-DD'))+1) else 0 end;
END; END IF;
